class Solution {
    public String maximumBinaryString(String binary) {
        int n = binary.length();
        if (n < 2) return binary;
        char[] s = binary.toCharArray();
        int zeros = 0, firstZero = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == '0') {
                if (firstZero == -1) firstZero = i;
                zeros++;
            }
        }
        if (zeros < 2) return binary;
        int pos = firstZero + zeros - 1;
        Arrays.fill(s, '1');
        if (pos < n) s[pos] = '0';
        return new String(s);
    }
}
```
